export const TEMPLATE_VERSION = '2026-05-20-v1';

// Helpers
export const PHASES: BuildPhase[] = ['Pre-Construction', 'Foundation', 'Framing', 'Rough-In', 'Pre-Drywall', 'Finish', 'Closeout'];
export const PHASE_ORDER: Record<BuildPhase, number> = { 'Pre-Construction': 0, 'Foundation': 1, 'Framing': 2, 'Rough-In': 3, 'Pre-Drywall': 4, 'Finish': 5, 'Closeout': 6 };

export function groupByCategory(items = SELECTIONS_TEMPLATE) {
  return items.reduce<Record<string, SelectionTemplateItem[]>>((acc, it) => {
    (acc[it.category] ||= []).push(it); return acc;
  }, {});
}

export function groupByPhase(items = SELECTIONS_TEMPLATE) {
  return items.reduce<Record<BuildPhase, SelectionTemplateItem[]>>((acc, it) => {
    (acc[it.phase] ||= [] as any).push(it); return acc;
  }, {} as Record<BuildPhase, SelectionTemplateItem[]>);
}